<template>
  <div>
    <form novalidate class="md-layout md-alignment-center-center">
      <md-card class="md-layout-item md-size-75 md-small-size-100">
        <md-card-header>
          <div class="md-title">🔴 Skype oznam</div>
        </md-card-header>

        <md-card-content>
          <md-field>
            <label for="age">Názov udalosti</label>
            <md-input
              type="text"
              name="eventName"
              autocomplete="eventName"
              v-model="eventName"
            />
          </md-field>

          <md-field :class="{ 'md-has-value': !!eventDate }">
            <label>Dátum a čas</label>
            <Datetime
              v-model="eventDate"
              type="datetime"
              :minute-step="10"
              :auto="true"
              title="Vyberte dátum a čas udalosti"
              input-class="md-input"
            />
          </md-field>

          <div class="md-layout md-gutter">
            <div class="md-layout-item md-small-size-100">
              <md-field>
                <label>{{ links.yt_tv.label }}</label>
                <md-textarea v-model="links.yt_tv.link" md-autogrow></md-textarea>
              </md-field>
              <md-field>
                <label>{{ links.yt_ts.label }}</label>
                <md-textarea v-model="links.yt_ts.link" md-autogrow></md-textarea>
              </md-field>
            </div>

            <div class="md-layout-item md-small-size-100">
              <md-field>
                <label>{{ links.fb_tv.label }}</label>
                <md-textarea v-model="links.fb_tv.link" md-autogrow></md-textarea>
              </md-field>
              <md-field>
                <label>{{ links.fb_ts_cz.label }}</label>
                <md-textarea v-model="links.fb_ts_cz.link" md-autogrow></md-textarea>
              </md-field>
              <md-field>
                <label>{{ links.fb_ts_sk.label }}</label>
                <md-textarea v-model="links.fb_ts_sk.link" md-autogrow></md-textarea>
              </md-field>
            </div>
          </div>

          <md-divider></md-divider>

          <md-field>
            <label>Text</label>
            <md-textarea :value="finalMessage" md-autogrow readonly></md-textarea>
          </md-field>
        </md-card-content>

        <md-card-actions>
          <md-switch v-model="isSkypeView">Zobraziť ako na Skype</md-switch>

          <md-button type="button" class="md-raised md-primary" @click="copyText()">
            <md-icon>content_copy</md-icon>
            <b>Kopírovať</b>
          </md-button>
        </md-card-actions>
      </md-card>
    </form>

    <md-snackbar :md-active.sync="showSnackbar" md-persistent>
      <span>Skopírované!</span>
      <md-button class="md-primary" @click="showSnackbar = false">OK</md-button>
    </md-snackbar>
  </div>
</template>

<script>
import { Datetime } from "vue-datetime";

export default {
  components: {
    Datetime,
  },
  data: () => ({
    eventName: "Mimořádné zprávy",
    eventDate: "2021-04-22T18:30:00.000Z",
    description: "",
    links: {
      yt_tv: {
        label: "YT ALLATRA TV Česko-Slovensko",
        link: "https://youtu.be/bviqgHG1s60",
      },
      yt_ts: {
        label: "YT Allatraunites. Tvořivá společnost",
        link: "https://youtu.be/kkD7K9oa1I4",
      },
      fb_tv: {
        label: "FB ALLATRA TV Česko-Slovensko",
        link: "https://www.facebook.com/AllatraTVceskoslovensko/posts/3677293875713477",
      },
      fb_ts_sk: {
        label: "FB Allatraunites. Tvorivá spoločnosť",
        link: "https://www.facebook.com/Allatraunites.sk/posts/484178622934310",
      },
      fb_ts_cz: {
        label: "FB Allatraunites. Tvořivá Společnost",
        link: "https://www.facebook.com/Allatraunites.cs/posts/759967821374206",
      },
    },
    showSnackbar: false,
    isSkypeView: false,
  }),
  computed: {
    eventDateFormatted() {
      const d = new Date(this.eventDate);

      const dayName = d.toLocaleString(window.navigator.language, {
        weekday: "long",
      });

      return (
        dayName +
        " – *" +
        d.toLocaleDateString() +
        "    " +
        d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) +
        "*"
      );
    },
    finalMessage() {
      const buildLinks = () => {
        return Object.entries(this.links)
          .filter(([, { link }]) => !!link)
          .map(([, { label, link }]) => `*${label}*\n` + `${this.escapeSkypeLink(link)}`)
          .join("\n");
      };

      return (
        `🔴 *${this.eventName}*\n` +
        `📅 ${this.eventDateFormatted}\n` +
        `──────────\n` +
        buildLinks() +
        "\n"
      );
    },
  },
  methods: {
    escapeSkypeLink(link) {
      return "```" + link + "```";
    },
    copyText() {
      console.log("Copying");
      this.$clipboard(this.finalMessage);
      this.showSnackbar = true;
    },
  },
};
</script>

<style lang="scss" scoped>
.vdatetime,
.vdatetime ::v-deep .vdatetime-input {
  width: 100%;
}
</style>
